  args: {},
  render: args => {
    const [open, setOpen] = useState<boolean>(Boolean(args.open));
    return <>
        <div style={{
        fontSize: 20,
        fontWeight: 700
      }} onClick={() => setOpen(true)}>
          열기
        </div>
        <BottomSheet {...args} open={open} onOpenChange={setOpen}>
          <section style={{
          minHeight: "200px"
        }}></section>
        </BottomSheet>
      </>;
  }
